#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long N, M;
        scanf("%lld %lld", &N, &M);
        long long ans;
        if ((N & 1) == 0 && (M & 1) == 0) ans = 0;
        else if ((N & 1) && (M & 1)) ans = N + M - 1;
        else if (N & 1) ans = M;
        else ans = N;
        printf("%lld\n", ans);
    }
    return 0;
}

