import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it)); M = int(next(it))
        if N % 2 == 0 and M % 2 == 0:
            out.append('0')
        elif N % 2 == 1 and M % 2 == 1:
            out.append(str(N + M - 1))
        elif N % 2 == 1:
            out.append(str(M))
        else:
            out.append(str(N))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

